Excellent! Now I have all the information I need. Let me compile a comprehensive report.

## Comprehensive VolumeChart Research Report

### 1. VolumeChart.tsx - Full Source Code

**File Path:** `/tmp/temporal-worktrees/task-volume-chart-001/frontend/src/features/analytics/VolumeChart.tsx`

**Full Source (Lines 1-184):**

```typescript
import type {
  AnalyticsInterval,
  MarketAnalyticsVolumeBucket,
} from "@/lib/api/types";
import { formatCurrency } from "@/lib/utils/format";
import { formatBucketRangeLabel, scaleNumber } from "./chartUtils";

interface VolumeChartProps {
  buckets: MarketAnalyticsVolumeBucket[];
  interval: AnalyticsInterval;
}

const WIDTH = 760;
const HEIGHT = 280;
const MARGIN = { top: 24, right: 24, bottom: 54, left: 52 };

export function VolumeChart({ buckets, interval }: VolumeChartProps) {
  const values = buckets.map((bucket) => bucket.volume);
  const maxVolume = values.length > 0 ? Math.max(...values) : 1;
  const innerWidth = WIDTH - MARGIN.left - MARGIN.right;
  const chartBottom = HEIGHT - MARGIN.bottom;
  const chartTop = MARGIN.top;
  const labelEvery = Math.max(1, Math.ceil(buckets.length / 5));
  const barWidth = Math.min(
    88,
    Math.max(30, innerWidth / Math.max(buckets.length * 1.4, 1)),
  );
  const midpoints = buckets.map((bucket) => {
    const start = Date.parse(bucket.bucketStart);
    const end = Date.parse(bucket.bucketEnd);
    return start + (end - start) / 2;
  });
  const domainStart = midpoints.length > 0 ? Math.min(...midpoints) : Date.now();
  const domainEnd = midpoints.length > 1 ? Math.max(...midpoints) : domainStart + 1;

  return (
    <section style={cardStyle}>
      <div style={headerStyle}>
        <div>
          <h2 style={titleStyle}>Activity Volume</h2>
          <p style={subtitleStyle}>
            Accepted trade and edit volume grouped into sparse UTC buckets.
          </p>
        </div>
      </div>

      <div style={{ overflowX: "auto" }}>
        <svg
          data-testid="volume-chart"
          role="img"
          aria-label="Activity volume chart"
          viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
          style={{ width: "100%", height: "auto", minWidth: 460 }}
        >
          {[0, 0.5, 1].map((ratio) => {
            const y = scaleNumber(ratio, 0, 1, chartBottom, chartTop);
            const value = maxVolume * ratio;
            return (
              <g key={ratio}>
                <line
                  x1={MARGIN.left}
                  y1={y}
                  x2={WIDTH - MARGIN.right}
                  y2={y}
                  stroke="rgba(139, 143, 163, 0.28)"
                  strokeDasharray="4 4"
                />
                <text
                  x={MARGIN.left - 10}
                  y={y + 4}
                  fill="var(--color-text-muted)"
                  fontSize="11"
                  textAnchor="end"
                >
                  {formatCurrency(value)}
                </text>
              </g>
            );
          })}

          <line
            x1={MARGIN.left}
            y1={chartBottom}
            x2={WIDTH - MARGIN.right}
            y2={chartBottom}
            stroke="var(--color-border)"
          />
          <line
            x1={MARGIN.left}
            y1={chartTop}
            x2={MARGIN.left}
            y2={chartBottom}
            stroke="var(--color-border)"
          />

          {buckets.map((bucket, index) => {
            const midpoint = midpoints[index] ?? domainStart;
            const xCenter =
              buckets.length === 1
                ? MARGIN.left + innerWidth / 2
                : scaleNumber(
                    midpoint,
                    domainStart,
                    domainEnd,
                    MARGIN.left + barWidth / 2,
                    WIDTH - MARGIN.right - barWidth / 2,
                  );
            const barHeight = scaleNumber(
              bucket.volume,
              0,
              maxVolume || 1,
              0,
              chartBottom - chartTop,
            );
            const x = xCenter - barWidth / 2;
            const y = chartBottom - barHeight;
            const showLabel = index % labelEvery === 0;

            return (
              <g key={`${bucket.bucketStart}-${bucket.bucketEnd}`}>
                <rect
                  x={x}
                  y={y}
                  width={barWidth}
                  height={barHeight}
                  rx="8"
                  fill="rgba(99, 102, 241, 0.75)"
                />
                <text
                  x={xCenter}
                  y={y - 8}
                  fill="var(--color-text)"
                  fontSize="11"
                  textAnchor="middle"
                >
                  {bucket.tradeCount}
                </text>
                {showLabel && (
                  <text
                    x={xCenter}
                    y={HEIGHT - 20}
                    fill="var(--color-text-muted)"
                    fontSize="11"
                    textAnchor="middle"
                  >
                    {formatBucketRangeLabel(
                      bucket.bucketStart,
                      bucket.bucketEnd,
                      interval,
                    )}
                  </text>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    </section>
  );
}

const cardStyle: React.CSSProperties = {
  padding: "var(--space-lg)",
  borderRadius: "var(--radius-lg)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg-surface)",
};

const headerStyle: React.CSSProperties = {
  marginBottom: "var(--space-md)",
};

const titleStyle: React.CSSProperties = {
  fontSize: "1.05rem",
  fontWeight: 600,
};

const subtitleStyle: React.CSSProperties = {
  marginTop: "var(--space-xs)",
  fontSize: "0.8rem",
  color: "var(--color-text-muted)",
  maxWidth: 480,
};
```

**Key Details:**
- **Tooltip Logic:** None. VolumeChart is a static SVG with no interactive tooltips.
- **Empty State Handling:** Lines 18-19: Uses ternary to set `maxVolume = 1` when `values.length === 0`, preventing division by zero
- **Bar Height Calculation:** Lines 108-114: Uses `scaleNumber()` to linearly map `bucket.volume` from domain [0, maxVolume] to range [0, chartBottom - chartTop]
- **Trade Count Labels:** Lines 129-137: Trade count is rendered as text above each bar at position (xCenter, y - 8) with `fontSize="11"`
- **SVG Structure:**
  - Grid lines and Y-axis labels (lines 55-79): 3 horizontal reference lines at ratios [0, 0.5, 1]
  - Axes borders (lines 81-94): Bottom and left axes
  - Bars (lines 121-128): `<rect>` elements with rounded corners (rx="8"), color `rgba(99, 102, 241, 0.75)`
  - Bucket labels: Rendered at bottom every Nth bucket (calculated by `labelEvery` on line 23)

